examples.fromCode:
class Logger {
public:
    virtual void log(const char* msg) = 0;
};

class ConsoleLogger : public Logger {
public:
    void log(const char* msg) override {
        printf("%s\n", msg);
    }
};

examples.toCode:
struct Logger {
    void (*log)(const char* msg);
};

void console_log(const char* msg) {
    printf("%s\n", msg);
}

void init_logger(struct Logger* l) {
    l->log = console_log;
}

