#include <memory>

void allocate() {
    auto buffer = std::make_unique<int[]>(100);
    buffer[0] = 5;
    // Automatically freed when it goes out of scope
}

examples.toCode:
#include <stdlib.h>

void allocate() {
    int* buffer = (int*)malloc(100 * sizeof(int));
    if (buffer == NULL) return;
    buffer[0] = 5;
    free(buffer); // Must be explicitly called to avoid leaks
}
